	ibark = pK*(d_initvalu_39*Frdy*FoRT)*(0.75*d_initvalu_35*exp(d_initvalu_39*FoRT)-0.75*Ko) /(exp(d_initvalu_39*FoRT)-1);
	ibarna_j = pNa*(d_initvalu_39*Frdy*FoRT) *(0.75*d_initvalu_32*exp(d_initvalu_39*FoRT)-0.75*Nao)  /(exp(d_initvalu_39*FoRT)-1);
	ibarna_sl = pNa*(d_initvalu_39*Frdy*FoRT) *(0.75*d_initvalu_33*exp(d_initvalu_39*FoRT)-0.75*Nao)  /(exp(d_initvalu_39*FoRT)-1);
	I_Ca_junc = (Fjunc_CaL*ibarca_j*d_initvalu_4*d_initvalu_5*(1-d_initvalu_6)*pow(Q10CaL,Qpow))*0.45;
	I_Ca_sl = (Fsl_CaL*ibarca_sl*d_initvalu_4*d_initvalu_5*(1-d_initvalu_7)*pow(Q10CaL,Qpow))*0.45;
	I_Ca = I_Ca_junc+I_Ca_sl;
	finavalu[offset_43]=-I_Ca*Cmem/(Vmyo*2*Frdy)*1e3;
	I_CaK = (ibark*d_initvalu_4*d_initvalu_5*(Fjunc_CaL*(1-d_initvalu_6)+Fsl_CaL*(1-d_initvalu_7))*pow(Q10CaL,Qpow))*0.45;
	I_CaNa_junc = (Fjunc_CaL*ibarna_j*d_initvalu_4*d_initvalu_5*(1-d_initvalu_6)*pow(Q10CaL,Qpow))*0.45;
	I_CaNa_sl = (Fsl_CaL*ibarna_sl*d_initvalu_4*d_initvalu_5*(1-d_initvalu_7)*pow(Q10CaL,Qpow))*0.45;

	Ka_junc = 1/(1+pow((Kdact/d_initvalu_36),3));
	Ka_sl = 1/(1+pow((Kdact/d_initvalu_37),3));
	s1_junc = exp(nu*d_initvalu_39*FoRT)*pow(d_initvalu_32,3)*Cao;
	s1_sl = exp(nu*d_initvalu_39*FoRT)*pow(d_initvalu_33,3)*Cao;
	s2_junc = exp((nu-1)*d_initvalu_39*FoRT)*pow(Nao,3)*d_initvalu_36;
	s3_junc = (KmCai*pow(Nao,3)*(1+pow((d_initvalu_32/KmNai),3))+pow(KmNao,3)*d_initvalu_36+ pow(KmNai,3)*Cao*(1+d_initvalu_36/KmCai)+KmCao*pow(d_initvalu_32,3)+pow(d_initvalu_32,3)*Cao+pow(Nao,3)*d_initvalu_36)*(1+ksat*exp((nu-1)*d_initvalu_39*FoRT));
	s2_sl = exp((nu-1)*d_initvalu_39*FoRT)*pow(Nao,3)*d_initvalu_37;
	s3_sl = (KmCai*pow(Nao,3)*(1+pow((d_initvalu_33/KmNai),3)) + pow(KmNao,3)*d_initvalu_37+pow(KmNai,3)*Cao*(1+d_initvalu_37/KmCai)+KmCao*pow(d_initvalu_33,3)+pow(d_initvalu_33,3)*Cao+pow(Nao,3)*d_initvalu_37)*(1+ksat*exp((nu-1)*d_initvalu_39*FoRT));
	I_ncx_junc = Fjunc*IbarNCX*pow(Q10NCX,Qpow)*Ka_junc*(s1_junc-s2_junc)/s3_junc;
	I_ncx_sl = Fsl*IbarNCX*pow(Q10NCX,Qpow)*Ka_sl*(s1_sl-s2_sl)/s3_sl;
	I_ncx = I_ncx_junc+I_ncx_sl;
	finavalu[offset_45]=2*I_ncx*Cmem/(Vmyo*2*Frdy)*1e3;

	I_pca_junc = Fjunc*pow(Q10SLCaP,Qpow)*IbarSLCaP*pow(d_initvalu_36,1.6)/(pow(KmPCa,1.6)+pow(d_initvalu_36,1.6));
	I_pca_sl = Fsl*pow(Q10SLCaP,Qpow)*IbarSLCaP*pow(d_initvalu_37,1.6)/(pow(KmPCa,1.6)+pow(d_initvalu_37,1.6));
	I_pca = I_pca_junc+I_pca_sl;
	finavalu[offset_44]=-I_pca*Cmem/(Vmyo*2*Frdy)*1e3;

	I_cabk_junc = Fjunc*GCaB*(d_initvalu_39-eca_junc);
	I_cabk_sl = Fsl*GCaB*(d_initvalu_39-eca_sl);
	I_cabk = I_cabk_junc+I_cabk_sl;
	finavalu[offset_46]=-I_cabk*Cmem/(Vmyo*2*Frdy)*1e3;

	MaxSR = 15;
	MinSR = 1;
	kCaSR = MaxSR - (MaxSR-MinSR)/(1+pow(ec50SR/d_initvalu_31,1.6));
	koSRCa = koCa/kCaSR;
	kiSRCa = kiCa*kCaSR;
	RI = 1-d_initvalu_14-d_initvalu_15-d_initvalu_16;
	finavalu[offset_14] = (kim*RI-kiSRCa*d_initvalu_36*d_initvalu_14)-(koSRCa*pow(d_initvalu_36,2)*d_initvalu_14-kom*d_initvalu_15);
	finavalu[offset_15] = (koSRCa*pow(d_initvalu_36,2)*d_initvalu_14-kom*d_initvalu_15)-(kiSRCa*d_initvalu_36*d_initvalu_15-kim*d_initvalu_16);
	finavalu[offset_16] = (kiSRCa*d_initvalu_36*d_initvalu_15-kim*d_initvalu_16)-(kom*d_initvalu_16-koSRCa*pow(d_initvalu_36,2)*RI);
	J_SRCarel = ks*d_initvalu_15*(d_initvalu_31-d_initvalu_36);
	J_serca = pow(Q10SRCaP,Qpow)*Vmax_SRCaP*(pow((d_initvalu_38/Kmf),hillSRCaP)-pow((d_initvalu_31/Kmr),hillSRCaP))
										 /(1+pow((d_initvalu_38/Kmf),hillSRCaP)+pow((d_initvalu_31/Kmr),hillSRCaP));
	J_SRleak = 5.348e-6*(d_initvalu_31-d_initvalu_36);

	finavalu[offset_17] = kon_na*d_initvalu_32*(Bmax_Naj-d_initvalu_17)-koff_na*d_initvalu_17;
	finavalu[offset_18] = kon_na*d_initvalu_33*(Bmax_Nasl-d_initvalu_18)-koff_na*d_initvalu_18;

	finavalu[offset_19] = kon_tncl*d_initvalu_38*(Bmax_TnClow-d_initvalu_19)-koff_tncl*d_initvalu_19;
	finavalu[offset_20] = kon_tnchca*d_initvalu_38*(Bmax_TnChigh-d_initvalu_20-d_initvalu_21)-koff_tnchca*d_initvalu_20;
	finavalu[offset_21] = kon_tnchmg*Mgi*(Bmax_TnChigh-d_initvalu_20-d_initvalu_21)-koff_tnchmg*d_initvalu_21;
	finavalu[offset_22] = 0;
	finavalu[offset_23] = kon_myoca*d_initvalu_38*(Bmax_myosin-d_initvalu_23-d_initvalu_24)-koff_myoca*d_initvalu_23;
	finavalu[offset_24] = kon_myomg*Mgi*(Bmax_myosin-d_initvalu_23-d_initvalu_24)-koff_myomg*d_initvalu_24;
	finavalu[offset_25] = kon_sr*d_initvalu_38*(Bmax_SR-d_initvalu_25)-koff_sr*d_initvalu_25;
	J_CaB_cytosol = finavalu[offset_19] + finavalu[offset_20] + finavalu[offset_21] + finavalu[offset_22] + finavalu[offset_23] + finavalu[offset_24] + finavalu[offset_25];

	finavalu[offset_26] = kon_sll*d_initvalu_36*(Bmax_SLlowj-d_initvalu_26)-koff_sll*d_initvalu_26;
	finavalu[offset_27] = kon_sll*d_initvalu_37*(Bmax_SLlowsl-d_initvalu_27)-koff_sll*d_initvalu_27;
	finavalu[offset_28] = kon_slh*d_initvalu_36*(Bmax_SLhighj-d_initvalu_28)-koff_slh*d_initvalu_28;
	finavalu[offset_29] = kon_slh*d_initvalu_37*(Bmax_SLhighsl-d_initvalu_29)-koff_slh*d_initvalu_29;
	J_CaB_junction = finavalu[offset_26]+finavalu[offset_28];
	J_CaB_sl = finavalu[offset_27]+finavalu[offset_29];

	finavalu[offset_30] = kon_csqn*d_initvalu_31*(Bmax_Csqn-d_initvalu_30)-koff_csqn*d_initvalu_30;
	oneovervsr = 1/Vsr;
	finavalu[offset_31] = J_serca*Vmyo*oneovervsr-(J_SRleak*Vmyo*oneovervsr+J_SRCarel)-finavalu[offset_30];

	I_Na_tot_junc = I_Na_junc+I_nabk_junc+3*I_ncx_junc+3*I_nak_junc+I_CaNa_junc;
	I_Na_tot_sl = I_Na_sl+I_nabk_sl+3*I_ncx_sl+3*I_nak_sl+I_CaNa_sl;
	finavalu[offset_32] = -I_Na_tot_junc*Cmem/(Vjunc*Frdy)+J_na_juncsl/Vjunc*(d_initvalu_33-d_initvalu_32)-finavalu[offset_17];
	oneovervsl = 1/Vsl;
	finavalu[offset_33] = -I_Na_tot_sl*Cmem*oneovervsl/Frdy+J_na_juncsl*oneovervsl*(d_initvalu_32-d_initvalu_33)+J_na_slmyo*oneovervsl*(d_initvalu_34-d_initvalu_33)-finavalu[offset_18];
	finavalu[offset_34] = J_na_slmyo/Vmyo*(d_initvalu_33-d_initvalu_34);

	I_K_tot = I_to+I_kr+I_ks+I_ki-2*I_nak+I_CaK+I_kp;
	finavalu[offset_35] = 0;

	I_Ca_tot_junc = I_Ca_junc+I_cabk_junc+I_pca_junc-2*I_ncx_junc;
	I_Ca_tot_sl = I_Ca_sl+I_cabk_sl+I_pca_sl-2*I_ncx_sl;
	finavalu[offset_36] = -I_Ca_tot_junc*Cmem/(Vjunc*2*Frdy)+J_ca_juncsl/Vjunc*(d_initvalu_37-d_initvalu_36)
	         - J_CaB_junction+(J_SRCarel)*Vsr/Vjunc+J_SRleak*Vmyo/Vjunc;
	finavalu[offset_37] = -I_Ca_tot_sl*Cmem/(Vsl*2*Frdy)+J_ca_juncsl/Vsl*(d_initvalu_36-d_initvalu_37)
	         + J_ca_slmyo/Vsl*(d_initvalu_38-d_initvalu_37)-J_CaB_sl;
	finavalu[offset_38] = -J_serca-J_CaB_cytosol +J_ca_slmyo/Vmyo*(d_initvalu_37-d_initvalu_38);

	state = 1;
	switch(state){
		case 0:
			I_app = 0;
			break;
		case 1:
			if(fmod(timeinst,cycleLength) <= 5){
				I_app = 9.5;
			}
			else{
				I_app = 0.0;
			}
			break;
		case 2:
			V_hold = -55;
			V_test = 0;
			if(timeinst>0.5 && timeinst<200.5){
				V_clamp = V_test;
			}
			else{
				V_clamp = V_hold;
			}
			R_clamp = 0.04;
			I_app = (V_clamp-d_initvalu_39)/R_clamp;
			break;
	}

	I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
	I_Cl_tot = I_ClCa+I_Clbk;
	I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
	I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
	finavalu[offset_39] = -(I_tot-I_app);

	finavalu[offset_41] = 0;
	finavalu[offset_42] = 0;
}

void kernel_cam_2(	fp timeinst,
					fp* initvalu,
					fp* finavalu,
					int valu_offset,
					fp* params,
					int params_offset,
					fp* com,
					int com_offset,
					fp Ca){

	fp Btot, CaMKIItot, CaNtot, PP1tot, K, Mg;
	int offset_1, offset_2, offset_3, offset_4, offset_5, offset_6, offset_7, offset_8, offset_9, offset_10;
	int offset_11, offset_12, offset_13, offset_14, offset_15;
	fp CaM, Ca2CaM, Ca4CaM, CaMB, Ca2CaMB, Ca4CaMB, Pb2, Pb, Pt, Pt2, Pa;
	fp Ca4CaN, CaMCa4CaN, Ca2CaMCa4CaN, Ca4CaMCa4CaN;
	fp Kd02, Kd24, k20, k02, k42, k24;
	fp k0Boff, k0Bon, k2Boff, k2Bon, k4Boff, k4Bon;
	fp k20B, k02B, k42B, k24B;
	fp kbi, kib, kpp1, Kmpp1, kib2, kb2i, kb24, kb42, kta, kat, kt42, kt24, kat2, kt2a;
	fp kcanCaoff, kcanCaon, kcanCaM4on, kcanCaM4off, kcanCaM2on, kcanCaM2off, kcanCaM0on, kcanCaM0off;
	fp k02can, k20can, k24can, k42can;
	fp rcn02, rcn24;
	fp B, rcn02B, rcn24B, rcn0B, rcn2B, rcn4B;
	fp Ca2CaN, rcnCa4CaN, rcn02CaN, rcn24CaN, rcn0CaN, rcn2CaN, rcn4CaN;
	fp Pix, rcnCKib2, rcnCKb2b, rcnCKib, T, kbt, rcnCKbt, rcnCKtt2, rcnCKta, rcnCKt2a, rcnCKt2b2, rcnCKai;
	fp dCaM, dCa2CaM, dCa4CaM, dCaMB, dCa2CaMB, dCa4CaMB;
	fp dPb2, dPb, dPt, dPt2, dPa;
	fp dCa4CaN, dCaMCa4CaN, dCa2CaMCa4CaN, dCa4CaMCa4CaN;

	Btot = params[params_offset+1];
	CaMKIItot = params[params_offset+2];
	CaNtot = params[params_offset+3];
	PP1tot = params[params_offset+4];
	K = params[16];
	Mg = params[17];

	offset_1 = valu_offset;
	offset_2 = valu_offset+1;
	offset_3 = valu_offset+2;
	offset_4 = valu_offset+3;
	offset_5 = valu_offset+4;
	offset_6 = valu_offset+5;
	offset_7 = valu_offset+6;
	offset_8 = valu_offset+7;
	offset_9 = valu_offset+8;
	offset_10 = valu_offset+9;
	offset_11 = valu_offset+10;
	offset_12 = valu_offset+11;
	offset_13 = valu_offset+12;
	offset_14 = valu_offset+13;
	offset_15 = valu_offset+14;

	CaM = initvalu[offset_1];
	Ca2CaM = initvalu[offset_2];
	Ca4CaM = initvalu[offset_3];
	CaMB = initvalu[offset_4];
	Ca2CaMB = initvalu[offset_5];
	Ca4CaMB = initvalu[offset_6];
	Pb2 = initvalu[offset_7];
	Pb = initvalu[offset_8];
	Pt = initvalu[offset_9];
	Pt2 = initvalu[offset_10];
	Pa = initvalu[offset_11];
	Ca4CaN = initvalu[offset_12];
	CaMCa4CaN = initvalu[offset_13];
	Ca2CaMCa4CaN = initvalu[offset_14];
	Ca4CaMCa4CaN = initvalu[offset_15];

	if (1 >= Mg){
		Kd02 = 0.0025*(1+K/0.94-Mg/0.012)*(1+K/8.1+Mg/0.022);
		Kd24 = 0.128*(1+K/0.64+Mg/0.0014)*(1+K/13.0-Mg/0.153);
	}
	else{
		Kd02 = 0.0025*(1+K/0.94-1/0.012+(Mg-1)/0.060)*(1+K/8.1+1/0.022+(Mg-1)/0.068);
		Kd24 = 0.128*(1+K/0.64+1/0.0014+(Mg-1)/0.005)*(1+K/13.0-1/0.153+(Mg-1)/0.150);
	}
	k20 = 10;
	k02 = k20/Kd02;
	k42 = 500;
	k24 = k42/Kd24;

	k0Boff = 0.0014;
	k0Bon = k0Boff/0.2;
	k2Boff = k0Boff/100;
	k2Bon = k0Bon;
	k4Boff = k2Boff;
	k4Bon = k0Bon;

	k20B = k20/100;
	k02B = k02;
	k42B = k42;
	k24B = k24;

	kbi = 2.2;
	kib = kbi/33.5e-3;
	kpp1 = 1.72;
	Kmpp1 = 11.5;
	kib2 = kib;
	kb2i = kib2*5;
	kb24 = k24;
	kb42 = k42*33.5e-3/5;
	kta = kbi/1000;
	kat = kib;
	kt42 = k42*33.5e-6/5;
	kt24 = k24;
	kat2 = kib;
	kt2a = kib*5;

	kcanCaoff = 1;
	kcanCaon = kcanCaoff/0.5;
	kcanCaM4on = 46;
	kcanCaM4off = 0.0013;
	kcanCaM2on = kcanCaM4on;
	kcanCaM2off = 2508*kcanCaM4off;
	kcanCaM0on = kcanCaM4on;
	kcanCaM0off = 165*kcanCaM2off;
	k02can = k02;
	k20can = k20/165;
	k24can = k24;
	k42can = k20/2508;

	rcn02 = k02*pow(Ca,2)*CaM - k20*Ca2CaM;
	rcn24 = k24*pow(Ca,2)*Ca2CaM - k42*Ca4CaM;

	B = Btot - CaMB - Ca2CaMB - Ca4CaMB;
	rcn02B = k02B*pow(Ca,2)*CaMB - k20B*Ca2CaMB;
	rcn24B = k24B*pow(Ca,2)*Ca2CaMB - k42B*Ca4CaMB;
	rcn0B = k0Bon*CaM*B - k0Boff*CaMB;
	rcn2B = k2Bon*Ca2CaM*B - k2Boff*Ca2CaMB;
	rcn4B = k4Bon*Ca4CaM*B - k4Boff*Ca4CaMB;

	Ca2CaN = CaNtot - Ca4CaN - CaMCa4CaN - Ca2CaMCa4CaN - Ca4CaMCa4CaN;
	rcnCa4CaN = kcanCaon*pow(Ca,2)*Ca2CaN - kcanCaoff*Ca4CaN;
	rcn02CaN = k02can*pow(Ca,2)*CaMCa4CaN - k20can*Ca2CaMCa4CaN;
	rcn24CaN = k24can*pow(Ca,2)*Ca2CaMCa4CaN - k42can*Ca4CaMCa4CaN;
	rcn0CaN = kcanCaM0on*CaM*Ca4CaN - kcanCaM0off*CaMCa4CaN;
	rcn2CaN = kcanCaM2on*Ca2CaM*Ca4CaN - kcanCaM2off*Ca2CaMCa4CaN;
	rcn4CaN = kcanCaM4on*Ca4CaM*Ca4CaN - kcanCaM4off*Ca4CaMCa4CaN;

	Pix = 1 - Pb2 - Pb - Pt - Pt2 - Pa;
	rcnCKib2 = kib2*Ca2CaM*Pix - kb2i*Pb2;
	rcnCKb2b = kb24*pow(Ca,2)*Pb2 - kb42*Pb;
	rcnCKib = kib*Ca4CaM*Pix - kbi*Pb;
	T = Pb + Pt + Pt2 + Pa;
	kbt = 0.055*T + 0.0074*pow(T,2) + 0.015*pow(T,3);
	rcnCKbt = kbt*Pb - kpp1*PP1tot*Pt/(Kmpp1+CaMKIItot*Pt);
	rcnCKtt2 = kt42*Pt - kt24*pow(Ca,2)*Pt2;
	rcnCKta = kta*Pt - kat*Ca4CaM*Pa;
	rcnCKt2a = kt2a*Pt2 - kat2*Ca2CaM*Pa;
	rcnCKt2b2 = kpp1*PP1tot*Pt2/(Kmpp1+CaMKIItot*Pt2);
	rcnCKai = kpp1*PP1tot*Pa/(Kmpp1+CaMKIItot*Pa);

	dCaM = 1e-3*(-rcn02 - rcn0B - rcn0CaN);
	dCa2CaM = 1e-3*(rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot*(-rcnCKib2 + rcnCKt2a) );
	dCa4CaM = 1e-3*(rcn24 - rcn4B - rcn4CaN + CaMKIItot*(-rcnCKib+rcnCKta) );
	dCaMB = 1e-3*(rcn0B-rcn02B);
	dCa2CaMB = 1e-3*(rcn02B + rcn2B - rcn24B);
	dCa4CaMB = 1e-3*(rcn24B + rcn4B);

	dPb2 = 1e-3*(rcnCKib2 - rcnCKb2b + rcnCKt2b2);
	dPb = 1e-3*(rcnCKib + rcnCKb2b - rcnCKbt);
	dPt = 1e-3*(rcnCKbt-rcnCKta-rcnCKtt2);
	dPt2 = 1e-3*(rcnCKtt2-rcnCKt2a-rcnCKt2b2);
	dPa = 1e-3*(rcnCKta+rcnCKt2a-rcnCKai);

	dCa4CaN = 1e-3*(rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN);
	dCaMCa4CaN = 1e-3*(rcn0CaN - rcn02CaN);
	dCa2CaMCa4CaN = 1e-3*(rcn2CaN+rcn02CaN-rcn24CaN);
	dCa4CaMCa4CaN = 1e-3*(rcn4CaN+rcn24CaN);

	finavalu[offset_1] = dCaM;
	finavalu[offset_2] = dCa2CaM;
	finavalu[offset_3] = dCa4CaM;
	finavalu[offset_4] = dCaMB;
	finavalu[offset_5] = dCa2CaMB;
	finavalu[offset_6] = dCa4CaMB;
	finavalu[offset_7] = dPb2;
	finavalu[offset_8] = dPb;
	finavalu[offset_9] = dPt;
	finavalu[offset_10] = dPt2;
	finavalu[offset_11] = dPa;
	finavalu[offset_12] = dCa4CaN;
	finavalu[offset_13] = dCaMCa4CaN;
	finavalu[offset_14] = dCa2CaMCa4CaN;
	finavalu[offset_15] = dCa4CaMCa4CaN;

	finavalu[com_offset] = 1e-3*(2*CaMKIItot*(rcnCKtt2-rcnCKb2b) - 2*(rcn02+rcn24+rcn02B+rcn24B+rcnCa4CaN+rcn02CaN+rcn24CaN));
}

void kernel_2(	int timeinst,
				fp* initvalu,
				fp* params,
				fp* finavalu,
				fp* com){

	int valu_offset_ecc, valu_offset_Dyad, valu_offset_SL, valu_offset_Cyt;
	int params_offset_Dyad, params_offset_SL, params_offset_Cyt;
	int com_offset_Dyad, com_offset_SL, com_offset_Cyt;
	fp CaDyad, CaSL, CaCyt;
	int i;

	valu_offset_ecc = 0;
	valu_offset_Dyad = 46;
	valu_offset_SL = 61;
	valu_offset_Cyt = 76;

	params_offset_Dyad = 0;
	params_offset_SL = 5;
	params_offset_Cyt = 10;

	com_offset_Dyad = 0;
	com_offset_SL = 1;
	com_offset_Cyt = 2;

	kernel_ecc_2(	timeinst,
					initvalu,
					finavalu,
					valu_offset_ecc,
					params);

	CaDyad = initvalu[35]*1e3;
	kernel_cam_2(	timeinst,
					initvalu,
					finavalu,
					valu_offset_Dyad,
					params,
					params_offset_Dyad,
					com,
					com_offset_Dyad,
					CaDyad);

	CaSL = initvalu[36]*1e3;
	kernel_cam_2(	timeinst,
					initvalu,
					finavalu,
					valu_offset_SL,
					params,
					params_offset_SL,
					com,
					com_offset_SL,
					CaSL);

	CaCyt = initvalu[37]*1e3;
	kernel_cam_2(	timeinst,
					initvalu,
					finavalu,
					valu_offset_Cyt,
					params,
					params_offset_Cyt,
					com,
					com_offset_Cyt,
					CaCyt);

	kernel_fin_2(	timeinst,
					initvalu,
					finavalu,
					valu_offset_ecc,
					valu_offset_Dyad,
					valu_offset_SL,
					valu_offset_Cyt,
					params,
					com);

	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){
			finavalu[i] = 0.0001;
		}
		else if (isinf(finavalu[i]) == 1){
			finavalu[i] = 0.0001;
		}
	}
}

void kernel_fin_2(	int timeinst,
					fp* initvalu,
					fp* finavalu,
					int offset_ecc,
					int offset_Dyad,
					int offset_SL,
					int offset_Cyt,
					fp* params,
					fp* com){

	fp BtotDyad, CaMKIItotDyad;
	fp Vmyo, Vdyad, VSL;
	fp kSLmyo, k0Boff, k0Bon, k2Boff, k2Bon, k4Bon;
	fp CaMtotDyad, Bdyad;
	fp J_cam_dyadSL, J_ca2cam_dyadSL, J_ca4cam_dyadSL;
	fp J_cam_SLmyo, J_ca2cam_SLmyo, J_ca4cam_SLmyo;

	BtotDyad = params[1];
	CaMKIItotDyad = params[2];

	finavalu[offset_ecc+35] = finavalu[offset_ecc+35] + 1e-3*com[0];
	finavalu[offset_ecc+36] = finavalu[offset_ecc+36] + 1e-3*com[1];
	finavalu[offset_ecc+37] = finavalu[offset_ecc+37] + 1e-3*com[2];

	Vmyo = 2.1454e-11;
	Vdyad = 1.7790e-14;
	VSL = 6.6013e-13;

	kSLmyo = 8.587e-15;
	k0Boff = 0.0014;
	k0Bon = k0Boff/0.2;
	k2Boff = k0Boff/100;
	k2Bon = k0Bon;
	k4Bon = k0Bon;

	CaMtotDyad = initvalu[offset_Dyad+0]
			   + initvalu[offset_Dyad+1]
			   + initvalu[offset_Dyad+2]
			   + initvalu[offset_Dyad+3]
			   + initvalu[offset_Dyad+4]
			   + initvalu[offset_Dyad+5]
			   + CaMKIItotDyad * (  initvalu[offset_Dyad+6]
								  + initvalu[offset_Dyad+7]
								  + initvalu[offset_Dyad+8]
								  + initvalu[offset_Dyad+9])
			   + initvalu[offset_Dyad+12]
			   + initvalu[offset_Dyad+13]
			   + initvalu[offset_Dyad+14];
	Bdyad = BtotDyad - CaMtotDyad;

	J_cam_dyadSL = 1e-3 * (  k0Boff*initvalu[offset_Dyad+0] - k0Bon*Bdyad*initvalu[offset_SL+0]);
	J_ca2cam_dyadSL = 1e-3 * (  k2Boff*initvalu[offset_Dyad+1] - k2Bon*Bdyad*initvalu[offset_SL+1]);
	J_ca4cam_dyadSL = 1e-3 * (  k2Boff*initvalu[offset_Dyad+2] - k4Bon*Bdyad*initvalu[offset_SL+2]);

	J_cam_SLmyo = kSLmyo * (  initvalu[offset_SL+0] - initvalu[offset_Cyt+0]);
	J_ca2cam_SLmyo = kSLmyo * (  initvalu[offset_SL+1] - initvalu[offset_Cyt+1]);
	J_ca4cam_SLmyo = kSLmyo * (  initvalu[offset_SL+2] - initvalu[offset_Cyt+2]);

	finavalu[offset_Dyad+0] = finavalu[offset_Dyad+0] - J_cam_dyadSL;
	finavalu[offset_Dyad+1] = finavalu[offset_Dyad+1] - J_ca2cam_dyadSL;
	finavalu[offset_Dyad+2] = finavalu[offset_Dyad+2] - J_ca4cam_dyadSL;

	finavalu[offset_SL+0] = finavalu[offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
	finavalu[offset_SL+1] = finavalu[offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
	finavalu[offset_SL+2] = finavalu[offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

	finavalu[offset_Cyt+0] = finavalu[offset_Cyt+0] + J_cam_SLmyo/Vmyo;
	finavalu[offset_Cyt+1] = finavalu[offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
	finavalu[offset_Cyt+2] = finavalu[offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

void embedded_fehlberg_7_8_2(	fp h,
								fp timeinst,
								fp* initvalu,
								fp* finavalu,
								fp* parameter,
								fp* error,
								fp* initvalu_temp,
								fp* finavalu_temp,
								fp* com) {

	const fp c_1_11 = 41.0 / 840.0;
	const fp c6 = 34.0 / 105.0;
	const fp c_7_8= 9.0 / 35.0;
	const fp c_9_10 = 9.0 / 280.0;

	const fp a2 = 2.0 / 27.0;
	const fp a3 = 1.0 / 9.0;
	const fp a4 = 1.0 / 6.0;
	const fp a5 = 5.0 / 12.0;
	const fp a6 = 1.0 / 2.0;
	const fp a7 = 5.0 / 6.0;
	const fp a8 = 1.0 / 6.0;
	const fp a9 = 2.0 / 3.0;
	const fp a10 = 1.0 / 3.0;

	const fp b31 = 1.0 / 36.0;
	const fp b32 = 3.0 / 36.0;
	const fp b41 = 1.0 / 24.0;
	const fp b43 = 3.0 / 24.0;
	const fp b51 = 20.0 / 48.0;
	const fp b53 = -75.0 / 48.0;
	const fp b54 = 75.0 / 48.0;
	const fp b61 = 1.0 / 20.0;
	const fp b64 = 5.0 / 20.0;
	const fp b65 = 4.0 / 20.0;
	const fp b71 = -25.0 / 108.0;
	const fp b74 =  125.0 / 108.0;
	const fp b75 = -260.0 / 108.0;
	const fp b76 =  250.0 / 108.0;
	const fp b81 = 31.0/300.0;
	const fp b85 = 61.0/225.0;
	const fp b86 = -2.0/9.0;
	const fp b87 = 13.0/900.0;
	const fp b91 = 2.0;
	const fp b94 = -53.0/6.0;
	const fp b95 = 704.0 / 45.0;
	const fp b96 = -107.0 / 9.0;
	const fp b97 = 67.0 / 90.0;
	const fp b98 = 3.0;
	const fp b10_1 = -91.0 / 108.0;
	const fp b10_4 = 23.0 / 108.0;
	const fp b10_5 = -976.0 / 135.0;
	const fp b10_6 = 311.0 / 54.0;
	const fp b10_7 = -19.0 / 60.0;
	const fp b10_8 = 17.0 / 6.0;
	const fp b10_9 = -1.0 / 12.0;
	const fp b11_1 = 2383.0 / 4100.0;
	const fp b11_4 = -341.0 / 164.0;
	const fp b11_5 = 4496.0 / 1025.0;
	const fp b11_6 = -301.0 / 82.0;
	const fp b11_7 = 2133.0 / 4100.0;
	const fp b11_8 = 45.0 / 82.0;
	const fp b11_9 = 45.0 / 164.0;
	const fp b11_10 = 18.0 / 41.0;
	const fp b12_1 = 3.0 / 205.0;
	const fp b12_6 = - 6.0 / 41.0;
	const fp b12_7 = - 3.0 / 205.0;
	const fp b12_8 = - 3.0 / 41.0;
	const fp b12_9 = 3.0 / 41.0;
	const fp b12_10 = 6.0 / 41.0;
	const fp b13_1 = -1777.0 / 4100.0;
	const fp b13_4 = -341.0 / 164.0;
	const fp b13_5 = 4496.0 / 1025.0;
	const fp b13_6 = -289.0 / 82.0;
	const fp b13_7 = 2193.0 / 4100.0;
	const fp b13_8 = 51.0 / 82.0;
	const fp b13_9 = 33.0 / 164.0;
	const fp b13_10 = 12.0 / 41.0;

	const fp err_factor  = -41.0 / 840.0;

	fp h2_7 = a2 * h;
	fp timeinst_temp;
	int i, j;

	for(j=0; j<13; j++){
		if(j==0){
			timeinst_temp = timeinst;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i];
			}
		}
		else if(1 == j){
			timeinst_temp = timeinst+h2_7;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h2_7 * (finavalu_temp[0*EQUATIONS+i]);
			}
		}
		else if(2 == j){
			timeinst_temp = timeinst+a3*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b31*finavalu_temp[0*EQUATIONS+i] + b32*finavalu_temp[1*EQUATIONS+i]);
			}
		}
		else if(j==3){
			timeinst_temp = timeinst+a4*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b41*finavalu_temp[0*EQUATIONS+i] + b43*finavalu_temp[2*EQUATIONS+i]);
			}
		}
		else if(4 == j){
			timeinst_temp = timeinst+a5*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b51*finavalu_temp[0*EQUATIONS+i] + b53*finavalu_temp[2*EQUATIONS+i] + b54*finavalu_temp[3*EQUATIONS+i]);
			}
		}
		else if(5 == j){
			timeinst_temp = timeinst+a6*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b61*finavalu_temp[0*EQUATIONS+i] + b64*finavalu_temp[3*EQUATIONS+i] + b65*finavalu_temp[4*EQUATIONS+i]);
			}
		}
		else if(6 == j){
			timeinst_temp = timeinst+a7*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b71*finavalu_temp[0*EQUATIONS+i] + b74*finavalu_temp[3*EQUATIONS+i] + b75*finavalu_temp[4*EQUATIONS+i] + b76*finavalu_temp[5*EQUATIONS+i]);
			}
		}
		else if(7 == j){
			timeinst_temp = timeinst+a8*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b81*finavalu_temp[0*EQUATIONS+i] + b85*finavalu_temp[4*EQUATIONS+i] + b86*finavalu_temp[5*EQUATIONS+i] + b87*finavalu_temp[6*EQUATIONS+i]);
			}
		}
		else if(8 == j){
			timeinst_temp = timeinst+a9*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b91*finavalu_temp[0*EQUATIONS+i] + b94*finavalu_temp[3*EQUATIONS+i] + b95*finavalu_temp[4*EQUATIONS+i] + b96*finavalu_temp[5*EQUATIONS+i] + b97*finavalu_temp[6*EQUATIONS+i]+ b98*finavalu_temp[7*EQUATIONS+i]);
			}
		}
		else if(9 == j){
			timeinst_temp = timeinst+a10*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b10_1*finavalu_temp[0*EQUATIONS+i] + b10_4*finavalu_temp[3*EQUATIONS+i] + b10_5*finavalu_temp[4*EQUATIONS+i] + b10_6*finavalu_temp[5*EQUATIONS+i] + b10_7*finavalu_temp[6*EQUATIONS+i] + b10_8*finavalu_temp[7*EQUATIONS+i] + b10_9*finavalu_temp[8*EQUATIONS+i]);
			}
		}
		else if(j==10){
			timeinst_temp = timeinst+h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b11_1*finavalu_temp[0*EQUATIONS+i] + b11_4*finavalu_temp[3*EQUATIONS+i] + b11_5*finavalu_temp[4*EQUATIONS+i] + b11_6*finavalu_temp[5*EQUATIONS+i] + b11_7*finavalu_temp[6*EQUATIONS+i] + b11_8*finavalu_temp[7*EQUATIONS+i] + b11_9*finavalu_temp[8*EQUATIONS+i]+ b11_10 * finavalu_temp[9*EQUATIONS+i]);
			}
		}
		else if(j==11){
			timeinst_temp = timeinst;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b12_1*finavalu_temp[0*EQUATIONS+i] + b12_6*finavalu_temp[5*EQUATIONS+i] + b12_7*finavalu_temp[6*EQUATIONS+i] + b12_8*finavalu_temp[7*EQUATIONS+i] + b12_9*finavalu_temp[8*EQUATIONS+i] + b12_10 * finavalu_temp[9*EQUATIONS+i]);
			}
		}
		else if(12 == j){
			timeinst_temp = timeinst+h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b13_1*finavalu_temp[0*EQUATIONS+i] + b13_4*finavalu_temp[3*EQUATIONS+i] + b13_5*finavalu_temp[4*EQUATIONS+i] + b13_6*finavalu_temp[5*EQUATIONS+i] + b13_7*finavalu_temp[6*EQUATIONS+i] + b13_8*finavalu_temp[7*EQUATIONS+i] + b13_9*finavalu_temp[8*EQUATIONS+i] + b13_10*finavalu_temp[9*EQUATIONS+i] + finavalu_temp[11*EQUATIONS+i]);
			}
		}

		kernel_2(	timeinst_temp,
					initvalu_temp,
					parameter,
					&finavalu_temp[j*EQUATIONS],
					com);
	}

	for(i=0; i<EQUATIONS; i++){
		finavalu[i]= initvalu[i] +  h * (c_1_11 * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i])  + c6 * finavalu_temp[5*EQUATIONS+i] + c_7_8 * (finavalu_temp[6*EQUATIONS+i] + finavalu_temp[7*EQUATIONS+i]) + c_9_10 * (finavalu_temp[8*EQUATIONS+i] + finavalu_temp[9*EQUATIONS+i]) );
	}

	for(i=0; i<EQUATIONS; i++){
		error[i] = fabs(err_factor * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i] - finavalu_temp[11*EQUATIONS+i] - finavalu_temp[12*EQUATIONS+i]));
	}
}

void solver_2(	int workload,
				int xmax,
				fp* x,
				fp* y,
				fp* params,
				fp* com,
				fp* err,
				fp* scale,
				fp* yy,
				fp* initvalu_temp,
				fp* finavalu_temp){

	fp err_exponent, h_init, h, tolerance;
	int xmin, error, outside;
	fp scale_min, scale_fina;
	int i, j, k, tid;
	long y_pointer_initial, y_pointer_current, x_pointer_current;
	int err_pointer, scale_pointer, yy_pointer, params_pointer, initvalu_temp_pointer, finavalu_temp_pointer, com_pointer;

	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax - xmin);

	if (xmax < xmin || h <= 0.0){
		return;
	}
	if (xmax == xmin){
		return;
	}
	if (h > (xmax - xmin) ){
		h = (fp)xmax - (fp)xmin;
	}

#pragma omp parallel for
	for(tid=0; tid<workload; tid++){
		err_pointer = tid*EQUATIONS;
		scale_pointer = tid*EQUATIONS;
		yy_pointer = tid*EQUATIONS;
		params_pointer = tid*PARAMETERS;
		initvalu_temp_pointer = tid*EQUATIONS;
		finavalu_temp_pointer = tid*13*EQUATIONS;
		com_pointer = tid*3;

		int failed = 0;

		for(k=1; k<(xmax+1); k++){
			y_pointer_initial = tid*((xmax+1)*EQUATIONS)+(k-1)*EQUATIONS;
			y_pointer_current = tid*((xmax+1)*EQUATIONS)+k*EQUATIONS;
			x_pointer_current = tid*(xmax+1)+k;

			x[x_pointer_current] = (fp)k;
			h = h_init;
			scale_fina = 1.0;

			for (j = 0; j < ATTEMPTS; j++){
				error = 0;
				outside = 0;
				scale_min = MAX_SCALE_FACTOR;

				embedded_fehlberg_7_8_2(	h,
											x[x_pointer_current],
											&y[y_pointer_initial],
											&y[y_pointer_current],
											&params[params_pointer],
											&err[err_pointer],
											&initvalu_temp[initvalu_temp_pointer],
											&finavalu_temp[finavalu_temp_pointer],
											&com[com_pointer]);

				for(i=0; i<EQUATIONS; i++){
					if(err[err_pointer+i] > 0){
						error = 1;
					}
				}
				if (error != 1){
					scale_fina = MAX_SCALE_FACTOR;
					break;
				}

				for(i=0; i<EQUATIONS; i++){
					if(y[y_pointer_initial+i] == 0.0){
						yy[yy_pointer+i] = tolerance;
					}
					else{
						yy[yy_pointer+i] = fabs(y[y_pointer_initial+i]);
					}
					scale[scale_pointer+i] = 0.8 * pow( tolerance * yy[yy_pointer+i] / err[err_pointer+i] , err_exponent );
					if(scale[scale_pointer+i]<scale_min){
						scale_min = scale[scale_pointer+i];
					}
				}
				scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

				for(i=0; i<EQUATIONS; i++){
					if ( err[err_pointer+i] > ( tolerance * yy[yy_pointer+i] ) ){
						outside = 1;
					}
				}
				if (outside == 0){
					break;
				}

				h = h * scale_fina;
				if (h >= 0.9){
					h = 0.9;
				}
				if ( x[x_pointer_current] + h > (fp)xmax ){
					h = (fp)xmax - x[x_pointer_current];
				}
				else if ( x[x_pointer_current] + h + 0.5 * h > (fp)xmax ){
					h = 0.5 * h;
				}
			}

			x[x_pointer_current] = x[x_pointer_current] + h;

			if ( j >= ATTEMPTS ){
				failed = 1;
				break;
			}
		}

		if (failed) {
			continue; 
		}
	}
}

int work_2(	int xmax,
			int workload){

	long long time0, time1, time2, time3, time4, time5, time6;
	long memory;
	int i, pointer;
	fp* y, *d_y;
	long y_mem;
	fp* x, *d_x;
	long x_mem;
	fp* params, *d_params;
	int params_mem;
	fp* d_com, *d_err, *d_scale, *d_yy, *d_initvalu_temp, *d_finavalu_temp;
	int com_mem, err_mem, scale_mem, yy_mem, initvalu_temp_mem, finavalu_temp_mem;

	time0 = get_time();

	memory = workload*(xmax+1)*EQUATIONS*4;
	if(memory>1000000000){
		printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
		return 0;
	}

	y_mem = workload * (xmax+1) * EQUATIONS * sizeof(fp);
	y= (fp *) malloc(y_mem);
	d_y = (fp *) malloc(y_mem);

	x_mem = workload * (xmax+1) * sizeof(fp);
	x= (fp *) malloc(x_mem);
	d_x = (fp *) malloc(x_mem);

	params_mem = workload * PARAMETERS * sizeof(fp);
	params= (fp *) malloc(params_mem);
	d_params = (fp *) malloc(params_mem);

	com_mem = workload * 3 * sizeof(fp);
	d_com = (fp *) malloc(com_mem);

	err_mem = workload * EQUATIONS * sizeof(fp);
	d_err = (fp *) malloc(err_mem);

	scale_mem = workload * EQUATIONS * sizeof(fp);
	d_scale = (fp *) malloc(scale_mem);

	yy_mem = workload * EQUATIONS * sizeof(fp);
	d_yy = (fp *) malloc(yy_mem);

	initvalu_temp_mem = workload * EQUATIONS * sizeof(fp);
	d_initvalu_temp = (fp *) malloc(initvalu_temp_mem);

	finavalu_temp_mem = workload * 13* EQUATIONS * sizeof(fp);
	d_finavalu_temp = (fp *) malloc(finavalu_temp_mem);

	time1 = get_time();

	for(i=0; i<workload; i++){
		pointer = i * (xmax+1) + 0;
		x[pointer] = 0;
	}
	for(i=0; i<workload; i++){
		memcpy(&d_x[i*(xmax+1)], &x[i*(xmax+1)], (xmax+1)*sizeof(fp));
	}

	for(i=0; i<workload; i++){
		pointer = i*((xmax+1)*EQUATIONS) + 0*(EQUATIONS);
		read("../../data/myocyte/y.txt",
				&y[pointer],
				91,
				1,
				0);
	}
	for(i=0; i<workload; i++){
		memcpy(&d_y[i*((xmax+1)*EQUATIONS)], &y[i*((xmax+1)*EQUATIONS)], (xmax+1)*EQUATIONS*sizeof(fp));
	}

	for(i=0; i<workload; i++){
		pointer = i*PARAMETERS;
		read("../../data/myocyte/params.txt",
				&params[pointer],
				18,
				1,
				0);
	}
	for(i=0; i<workload; i++){
		memcpy(&d_params[i*PARAMETERS], &params[i*PARAMETERS], PARAMETERS*sizeof(fp));
	}

