					int data_rows, 
					int data_cols,
					int major){

	FILE* fid;
	int i, j;
	fp temp;
	int res;

	fid = fopen(filename, "r");
	if( fid == NULL ){
		printf( "The file was not opened for reading\n" );
		return;
	}

	if(major==0){
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				res = fscanf(fid, "%f", &temp);
				if (res != 1) {
					printf("Error reading file\n");
					fclose(fid);
					return;
				}
				input[i*data_cols+j] = (fp)temp;
			}
		}
	}
	else{
		for(i=0; i<data_rows; i++){
