	}

	for(i=0; i<EQUATIONS; i++){
		error[i] = fabs(err_factor * (finavalu_temp[0][i] + finavalu_temp[10][i] - finavalu_temp[11][i] - finavalu_temp[12][i]));
	}

	free(initvalu_temp);
	for (i= 0; 13 > i; i++){
		free(finavalu_temp[i]);
	}
	free(finavalu_temp);
}

int solver(	fp** y,
			fp* x,
			int xmax,
			fp* params,
			fp* com,
			fp* d_initvalu,
			fp* d_finavalu,
			fp* d_params,
			fp* d_com) {

	fp err_exponent, h_init, h, tolerance;
	int error, outside, xmin;
	fp scale_min, scale_fina;
	fp* err, *scale, *yy;
	int i, j, k;

	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	x[0] = 0;

	if (xmin > xmax || 0.0 >= h){
		return -2;
	}
	if (xmin == xmax){
		return 0;
	}
	if (h > (xmax - xmin) ){
		h = (fp)xmax - (fp)xmin;
	}

	err= (fp *) malloc(EQUATIONS* sizeof(fp));
	scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	for(k=1; k<=xmax; k++){
		x[k] = k-1;
		h = h_init;
		scale_fina = 1.0;

		for (j = 0; ATTEMPTS > j; j++){
			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(	x[k],
									h,
									y[k-1],
									y[k],
									err,
									params,
									com,
									d_initvalu,
									d_finavalu,
									d_params,
									d_com);

			for(i=0; i<EQUATIONS; i++){
				if(0 < err[i]){
					error = 1;
				}
			}
			if (error != 1){
				scale_fina = MAX_SCALE_FACTOR;
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(0.0 == y[k-1][i]){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
				}
				scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i]<scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( ( tolerance * yy[i] ) < err[i] ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;
			if (0.9 <= h){
				h = 0.9;
			}
			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}
			else if ( x[k] + h + 0.5 * h > (fp)xmax ){
				h = 0.5 * h;
			}
		}

		x[k] = x[k] + h;

		if ( ATTEMPTS <= j ){
			free(err);
			free(scale);
			free(yy);
			return -1;
		}
	}

	free(err);
	free(scale);
	free(yy);

	return 0;
}

int work(	int xmax,
			int workload){

	long long time0, time1, time2, time3, time4, time5;
	long long memory;
	int i, j, status;
	fp*** y;
	fp** x;
	fp** params;
	fp* com;
	fp* d_initvalu, *d_finavalu, *d_params, *d_com;

	time0 = get_time();

	memory = workload*(xmax+1)*EQUATIONS*4;
	if(memory>1000000000){
		printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
		return 0;
	}

	y = (fp ***) malloc(workload* sizeof(fp **));
	for(i=0; i<workload; i++){
		y[i] = (fp**)malloc((1+xmax)*sizeof(fp*));
		for(j=0; j<(1+xmax); j++){
			y[i][j]= (fp *) malloc(EQUATIONS* sizeof(fp));
		}
	}

	x = (fp **) malloc(workload * sizeof(fp *));
	for (i= 0; i<workload; i++){
		x[i]= (fp *)malloc((1+xmax) *sizeof(fp));
	}

	params = (fp **) malloc(workload * sizeof(fp *));
	for (i= 0; i<workload; i++){
		params[i]= (fp *)malloc(PARAMETERS * sizeof(fp));
	}

	com = (fp*)malloc(3 * sizeof(fp));

	d_initvalu = (fp*)malloc(EQUATIONS * sizeof(fp));
	d_finavalu = (fp*)malloc(EQUATIONS * sizeof(fp));
	d_params = (fp*)malloc(PARAMETERS * sizeof(fp));
	d_com = (fp*)malloc(3 * sizeof(fp));

	time1 = get_time();

	for(i=0; i<workload; i++){
		read(	"../../data/myocyte/y.txt",
				y[i][0],
				EQUATIONS,
				1,
				0);
	}

	for(i=0; i<workload; i++){
		read("../../data/myocyte/params.txt",
				params[i],
				PARAMETERS,
				1,
				0);
	}

	time2 = get_time();

	for(i=0; i<workload; i++){
		status = solver(	y[i],
							x[i],
							xmax,
							params[i],
							com,
							d_initvalu,
							d_finavalu,
							d_params,
							d_com);

		if(status !=0){
			printf("STATUS: %d\n", status);
		}
	}

	FILE * pFile;
	pFile = fopen ("output.txt","w");
	if (pFile==NULL){
		fputs ("fopen example",pFile);
		return -1;
	}

	int k;
	for(i=0; i<workload; i++){
		fprintf(pFile, "WORKLOAD %d:\n", i);
		for(j=0; j<(xmax+1); j++){
			fprintf(pFile, "\tTIME %d:\n", j);
			for(k=0; k<EQUATIONS; k++){
				fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
			}
		}
	}

	fclose (pFile);

	time3 = get_time();

	for (i= 0; i< workload; i++){
		for (j= 0; j< (1+xmax); j++){
			free(y[i][j]);
		}
		free(y[i]);
	}
	free(y);

	for (i= 0; i< workload; i++){
		free(x[i]);
	}
	free(x);

	for (i= 0; i< workload; i++){
		free(params[i]);
	}
	free(params);

	free(com);
	free(d_initvalu);
	free(d_finavalu);
	free(d_params);
	free(d_com);

	time4 = get_time();

	printf("Time spent in different stages of the application:\n");
	printf("%.12f s, %.12f % : SETUP VARIABLES\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time4-time0) * 100);
	printf("%.12f s, %.12f % : ALLOCATE CPU MEMORY AND GPU MEMORY\n", (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time4-time0) * 100);
	printf("%.12f s, %.12f % : READ DATA FROM FILES\n", (float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time4-time0) * 100);
	printf("%.12f s, %.12f % : RUN COMPUTATION\n", (float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time4-time0) * 100);
	printf("%.12f s, %.12f % : FREE MEMORY\n", (float) (time4-time4) / 1000000, (float) (time4-time4) / (float) (time4-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float) (time4-time0) / 1000000);

	return 0;
}

int main(int argc, char *argv []){
	int xmax, workload, mode;

	if(4 != argc){
		printf("ERROR: %d is the incorrect number of arguments, the number of arguments must be 3\n", argc-1);
		return 0;
	}
	else{
		xmax = atoi(argv[1]);
		if(0 > xmax){
			printf("ERROR: %d is the incorrect end of simulation interval, use numbers > 0\n", xmax);
			return 0;
		}

		workload = atoi(argv[2]);
		if(workload<0){
			printf("ERROR: %d is the incorrect number of instances of simulation, use numbers > 0\n", workload);
			return 0;
		}

		mode = 0;
		mode = atoi(argv[3]);
		if(0 != mode && mode != 1){
			printf("ERROR: %d is the incorrect mode, it should be omitted or equal to 0 or 1\n", mode);
			return 0;
		}
	}

	if(mode == 0){
		work(	xmax, workload);
	}
	else{
		printf("Mode 1 not implemented in this translation file.\n");
	}

	return 0;
}
